import Foundation

func solve(grid: Array<Array<Int64>>, k: Int64) -> Int64 {
    let m = grid.count
    let n = grid[0].count
    var visited = [[Bool]](repeating: [Bool](repeating: false, count: n), count: m)
    var count = 0

    for i in 0..<m {
        for j in 0..<n {
            if grid[i][j] != 0 && !visited[i][j] {
                var stack = [(i, j)]
                visited[i][j] = true
                var sum = Int64(grid[i][j])
                var mod = sum % k

                while !stack.isEmpty {
                    let (x, y) = stack.removeLast()
                    for (dx, dy) in [(0, 1), (1, 0), (0, -1), (-1, 0)] {
                        let nx = x + dx
                        let ny = y + dy
                        if nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] != 0 {
                            visited[nx][ny] = true
                            sum += Int64(grid[nx][ny])
                            mod = sum % k
                            stack.append((nx, ny))
                        }
                    }
                }

                if mod == 0 {
                    count += 1
                }
            }
        }
    }

    return Int64(count)
}
